"use client";
// Generated by OrchestKit Claude Plugin
// D2 component lift (docs-site design overhaul)

import { useEffect, useRef } from "react";

interface FlickeringGridProps {
  className?: string;
  /** square size in px (default 3) */
  squareSize?: number;
  /** gap between squares in px (default 6) */
  gridGap?: number;
  /** per-frame probability a square changes opacity (default 0.03) */
  flickerChance?: number;
  /** max square opacity (default 0.35) */
  maxOpacity?: number;
  /** square color — any CSS color; defaults to the fd primary token */
  color?: string;
}

/**
 * FlickeringGrid — a canvas of tiny squares that randomly flicker their
 * opacity, forming an ambient animated backdrop. Sizes itself to its parent
 * via ResizeObserver and is a non-interactive layer (pointer-events-none is
 * baked in), so it can be dropped behind content with an absolute className.
 *
 * Motion: under prefers-reduced-motion the grid renders one static frame and
 * stops (no flicker), respecting the user's preference.
 */
export function FlickeringGrid({
  className,
  squareSize = 3,
  gridGap = 6,
  flickerChance = 0.03,
  maxOpacity = 0.35,
  color = "var(--color-fd-primary)",
}: FlickeringGridProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    // Resolve the requested color to a concrete rgb via a probe element so we
    // can vary only the alpha per square (CSS custom props aren't usable in
    // canvas fillStyle directly).
    const probe = document.createElement("div");
    probe.style.color = color;
    document.body.appendChild(probe);
    const resolved = getComputedStyle(probe).color || "rgb(16, 185, 129)";
    document.body.removeChild(probe);
    const rgb = resolved.match(/\d+(\.\d+)?/g)?.slice(0, 3).join(", ") ?? "16, 185, 129";

    const dpr = Math.min(window.devicePixelRatio || 1, 2);
    let cols = 0;
    let rows = 0;
    let squares: Float32Array = new Float32Array(0);
    const cell = squareSize + gridGap;

    const setup = () => {
      const w = container.clientWidth;
      const h = container.clientHeight;
      canvas.width = Math.max(1, Math.floor(w * dpr));
      canvas.height = Math.max(1, Math.floor(h * dpr));
      canvas.style.width = `${w}px`;
      canvas.style.height = `${h}px`;
      cols = Math.ceil(w / cell);
      rows = Math.ceil(h / cell);
      squares = new Float32Array(cols * rows);
      for (let i = 0; i < squares.length; i++) {
        squares[i] = Math.random() * maxOpacity;
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      for (let c = 0; c < cols; c++) {
        for (let r = 0; r < rows; r++) {
          const opacity = squares[c * rows + r];
          ctx.fillStyle = `rgba(${rgb}, ${opacity})`;
          ctx.fillRect(
            c * cell * dpr,
            r * cell * dpr,
            squareSize * dpr,
            squareSize * dpr
          );
        }
      }
    };

    const prefersReduced = window.matchMedia(
      "(prefers-reduced-motion: reduce)"
    ).matches;

    setup();
    draw();

    let raf = 0;
    const tick = () => {
      for (let i = 0; i < squares.length; i++) {
        if (Math.random() < flickerChance) {
          squares[i] = Math.random() * maxOpacity;
        }
      }
      draw();
      raf = requestAnimationFrame(tick);
    };

    // Only animate while on-screen. A hero grid on a 273-page docs site would
    // otherwise burn CPU/battery flickering off-screen for the whole visit.
    // IntersectionObserver starts/stops the rAF loop; reduced-motion never runs
    // it (the one static frame above is the final visual).
    let running = false;
    const startLoop = () => {
      if (running || prefersReduced) return;
      running = true;
      raf = requestAnimationFrame(tick);
    };
    const stopLoop = () => {
      running = false;
      if (raf) cancelAnimationFrame(raf);
      raf = 0;
    };

    const io = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (entry.isIntersecting) startLoop();
          else stopLoop();
        }
      },
      { threshold: 0 }
    );
    io.observe(container);

    const ro = new ResizeObserver(() => {
      setup();
      draw();
    });
    ro.observe(container);

    return () => {
      stopLoop();
      io.disconnect();
      ro.disconnect();
    };
  }, [squareSize, gridGap, flickerChance, maxOpacity, color]);

  return (
    <div
      ref={containerRef}
      aria-hidden
      className={`pointer-events-none ${className ?? ""}`}
    >
      <canvas ref={canvasRef} className="block h-full w-full" />
    </div>
  );
}

export default FlickeringGrid;
